        <div className="absolute inset-0 z-[3]">
          <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-b from-[#020202] via-transparent to-[#020202] opacity-80" />
          <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-r from-[#020202] via-[#020202]/40 to-transparent" />
        </div>

        {/* Subtle grid pattern for premium feel */}
        <div className="absolute inset-0 z-[2] opacity-[0.03] bg-[linear-gradient(rgba(59,130,246,0.1)_1px,transparent_1px),linear-gradient(90deg,rgba(59,130,246,0.1)_1px,transparent_1px)] bg-[size:60px_60px]" />
