                      <div className="flex items-center gap-3 mb-1.5 md:mb-2">
                        <Icon size={18} className="text-primary/60 group-hover:text-primary transition-colors flex-shrink-0" />
                        <h3 className="text-white text-lg md:text-xl font-bold tracking-tight group-hover:text-primary transition-colors">
                          {item.title}
                        </h3>
                      </div>
                      <p className="text-white/40 group-hover:text-white/60 transition-colors text-sm md:text-sm leading-tight md:leading-relaxed font-medium">
                        {item.description}
