const Section: React.FC<SectionProps> = ({ 
  isActive, 
  subtitle, 
  title, 
  content, 
  showButton, 
  buttonText, 
  backgroundImage,
  id 
}) => {
  const [isLoaded, setIsLoaded] = useState(false);
  const sectionRef = useRef<HTMLElement>(null);
  const isHero = id === 'hero';

  const { scrollYProgress } = useScroll({
    target: sectionRef,
    offset: ["start end", "end start"]
  });

  const backgroundY = useTransform(scrollYProgress, [0, 1], ["-12%", "12%"]);

  useEffect(() => {
    if (backgroundImage) {
      const img = new Image();
      img.src = backgroundImage;
      img.onload = () => setIsLoaded(true);
      img.onerror = () => {
        console.error("Failed to load image:", backgroundImage);
        setIsLoaded(true); // Still show the section even if image fails
      };
    } else {
      setIsLoaded(true);
    }
  }, [backgroundImage]);

  return (
    <section 
      id={id} 
      ref={sectionRef}
      className="relative h-[100dvh] w-full snap-child flex flex-col justify-center overflow-hidden bg-surface"
      style={{ scrollSnapAlign: 'start', scrollSnapStop: 'always' }}
    >
      <div className="absolute inset-0 z-0 overflow-hidden">
        <AnimatePresence mode="wait">
          {backgroundImage && isLoaded && (
            <motion.div 
              key={backgroundImage}
              initial={{ opacity: 0, scale: 1.1 }}
              animate={isActive ? { 
                opacity: isHero ? 0.45 : 0.35, 
                scale: 1 
              } : { opacity: 0, scale: 1.1 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 1.2, ease: [0.22, 1, 0.36, 1] }}
              className="absolute inset-0 z-0 bg-cover bg-center grayscale-[0.1] brightness-[0.8]"
              style={{ 
                y: backgroundY, 
                backgroundImage: `url(${backgroundImage})` 
              }}
            />
          )}
        </AnimatePresence>

        {isHero && <TechBackgroundLayer />}

        <div className="absolute inset-0 z-[3] pointer-events-none">
          <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-b from-surface via-transparent to-surface opacity-80" />
          <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-r from-surface via-surface/40 to-transparent" />
        </div>
      </div>

      <div className="relative z-10 px-6 md:px-20 lg:px-32 max-w-7xl w-full mx-auto">
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={isActive ? { opacity: 1, y: 0 } : { opacity: 0, y: 30 }}
          transition={{ duration: 0.8, ease: "easeOut" }}
        >
          {subtitle && <div className="mb-2">{subtitle}</div>}

          <h1 className="text-4xl md:text-5xl lg:text-7xl xl:text-8xl font-heading font-extrabold tracking-[-0.06em] mb-6 md:mb-8 text-white leading-[0.9] flex items-baseline">
            {title}<BrandingSeal />
          </h1>

          {content && (
            <p className="text-sm md:text-lg lg:text-xl text-white/60 max-w-2xl leading-[1.6] mb-8 md:mb-12 font-medium tracking-tight">
              {content}
            </p>
          )}

          {showButton && (
            <motion.button 
              whileHover={{ scale: 1.05, x: 8 }}
              whileTap={{ scale: 0.95 }}
              className="group bg-primary text-white font-bold py-3 px-8 md:py-6 md:px-16 rounded-xl flex items-center justify-center gap-4 transition-all shadow-2xl shadow-primary/30 w-fit"
            >
              <span className="text-[10px] md:text-[11px] uppercase tracking-[0.3em] font-black">{buttonText}</span>
              <ArrowRight size={20} className="group-hover:translate-x-2 transition-transform" />
            </motion.button>
          )}
        </motion.div>
      </div>

      {isHero && (
        <motion.div 
          initial={{ opacity: 0 }}
          animate={isActive ? { opacity: 0.8 } : {}}
          className="absolute bottom-10 left-6 md:left-20 lg:left-32 flex flex-col items-center gap-3"
        >
          <span className="font-mono text-[8px] tracking-[0.5em] uppercase font-black text-white/50">SCROLL</span>
          <div className="w-[1px] h-12 bg-white/10 relative overflow-hidden">
