const TechBackgroundLayer: React.FC = () => {
  const elements = useMemo(() => Array.from({ length: 12 }).map((_, i) => ({
    id: i,
    x: Math.random() * 100,
    y: Math.random() * 100,
    duration: Math.random() * 15 + 10,
    char: ['0', '1', '<', '>', '{', '}', '/', '#'][Math.floor(Math.random() * 8)]
  })), []);

  return (
    <div className="absolute inset-0 z-[2] overflow-hidden pointer-events-none opacity-30">
      {elements.map((el) => (
        <motion.div
          key={el.id}
          initial={{ opacity: 0, x: `${el.x}%`, y: `${el.y}%` }}
          animate={{
            opacity: [0, 0.4, 0],
            y: [`${el.y}%`, `${el.y - 15}%`],
          }}
          transition={{
            duration: el.duration,
            repeat: Infinity,
            ease: "linear",
            delay: el.id * 0.4
          }}
          className="absolute font-mono text-primary text-[10px] font-bold"
        >
          {el.char}
        </motion.div>
      ))}
    </div>
  );
};

